onClick:
{{
  !Input1.isValid 
    ? showAlert('Por favor, completa los campos requeridos del formulario.', 'warning')
    : (items_table_modal.updatedRowIndices && items_table_modal.updatedRowIndices.length > 0)
      ? showAlert('Tienes cambios pendientes en las líneas de los ítems. Debes presionar el botón de guardar (check verde) en la línea antes de poder Confirmar.', 'warning')
      : updateOrden.run()
          .then(() => insertItemsNuevos.run())       // si usas dos queries
          .then(() => updateItemsExistentes.run())
          // .then(() => upsertItems.run())          // si usabas una sola
          .then(() => {
            // 🆕 Refrescar la tabla de órdenes pendientes
            return obtener_listado_ordenes.run();
          })
          .then(() => {
            closeModal('mdl_detalle_orden');
            storeValue('orden_editable', undefined);
            storeValue('items_editables', []);
            showAlert('¡Orden y productos actualizados correctamente!', 'success');
          })
          .catch((error) => {
            showAlert('Hubo un error al guardar los cambios: ' + error.message, 'error');
          })
}}
